/*
注意：该书源【搜索】启用了 "人机验证"，因此使用过程中（搜索、换书源）可能会出现验证码界面，如果不喜欢可以禁用该书源。
其他和该网站界面类似的，一般都可以直接改源URL地址(sourceURL)域名来切换网站。
*/
try{
	c2=result.match(/c2="(.*?)"/)[1]
	u2=result.match(/src="(.*?)"/)[1]
	origin=baseUrl.match(/[^.]+[^/]+/)[0]
	str=java.ajax(origin+u2).match(/function.*\(\)\}/)[0]
	eval(str);temp=ajax(c2)
	java.ajax(origin+temp)
 if(baseUrl.match(/sscc/)){
 	u=java.get("url")}else{u=baseUrl}
 	//java.log(u)
	result=java.ajax(u)
}catch(err){result}

exploreUrl:
@js:
 sort=[];
 push=(title,url,type)=>sort.push({
		title: title,
		url: url,
		style: {
				layout_flexGrow: 1,
				layout_flexBasisPercent: type
			}
	});
	u=source.getKey();
	url=u+"/menu.html";
	D=org.jsoup.Jsoup.parse(java.ajax(url));
	A=D.select('div[class="divmen"] a');
	for(i in A){
		if(i!=0&&i!=4&&i!=5){
			push(A[i].text(),A[i].attr("href"),"0.25")
		}
	}
	JSON.stringify(sort);

searchUrl:
@js:
try{
bUrl=baseUrl.replace(/\/?\#\#.*/,'');
cookie.removeCookie(bUrl)
s=String(java.ajax(bUrl))
act=s.match(/"act".*?"(.{16})"/)[1]
sub=s.match(/name="submit".*?value="(.*?)"/)[1]
body=String("act="+act+"&q="+key+"&submit="+sub)
xx=body.match(/[^&=]+/g)
for(i in xx){
re=java.encodeURI(xx[i],"gbk")
body=body.replace(xx[i],re)
 }
var url=String(bUrl+"/sscc/,"+JSON.stringify({
	"method":"POST","body":body}))
java.put("key",body.match(/q=([^&]*)/)[1]);
java.put("url",bUrl+"/sscc/"+java.post(bUrl+"/sscc/",body,{}).header("Location"));url
}catch{java.longToast("获取失败")}

